+        let (model_name, model_family, total_tokens) = if workspace_id == workspace_a_id {
+            (
+                Some("gpt-4o-mini".to_string()),
+                Some("gpt-4o".to_string()),
+                workspace_a_totals.next().expect("workspace-a token total"),
+            )
